/bin/zsh -lc "node - <<'NODE'
const path = require('path');
const { planExtraction } = require('./src/archive/safeExtract');
const base = path.resolve('/tmp/extract');
const ok = planExtraction([{ name: 'a/file.txt' }, { name: 'nested/b.txt' }], base);
console.assert(ok.length === 2, 'keeps normal entries');
console.assert(ok[0].target === path.resolve(base, 'a/file.txt'), 'returns resolved target');
for (const name of ['../escape.txt', '/tmp/escape.txt', '../extract-sibling/file.txt']) {
  let threw = false;
  try {
    planExtraction([{ name }], base);
  } catch (error) {
    threw = error.message === 'unsafe path';
  }
  console.assert(threw, "'`rejects ${name}`);
}
NODE'

